import React, { useState, useEffect, useRef } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { formatDisplayName } from '../utils/nameFormatter';
import { gamesAPI } from '../services/api';
import { showNotification } from '../assets/notifications';

interface Game {
  _id: string;
  title: string;
  description: string;
  price: number;
  originalPrice?: number;
  discount?: number;
  platform: string;
  region: string;
  images: string[];
  availability: string;
  isNew?: boolean;
}

const Home: React.FC = () => {
  const [games, setGames] = useState<Game[]>([]);
  const [filteredGames, setFilteredGames] = useState<Game[]>([]);
  const [loading, setLoading] = useState(true);
  const [favorites, setFavorites] = useState<string[]>([]);
  const [searchParams, setSearchParams] = useSearchParams();
  const [selectedPlatform, setSelectedPlatform] = useState<string>('');
  const [showFilters, setShowFilters] = useState(false);
  const productsRef = useRef<HTMLDivElement>(null);
  const { state } = useAuth();

  const searchQuery = searchParams.get('search') || '';
  const platforms = ['PC', 'Xbox', 'PlayStation', 'Mobile'];

  useEffect(() => {
    fetchGames();
    loadFavorites();
  }, []);

  const loadFavorites = () => {
    const savedFavorites = localStorage.getItem('favoriteGames');
    if (savedFavorites) {
      setFavorites(JSON.parse(savedFavorites));
    }
  };

  const toggleFavorite = (gameId: string) => {
    let newFavorites;
    if (favorites.includes(gameId)) {
      newFavorites = favorites.filter(id => id !== gameId);
      showNotification('تم إزالة اللعبة من المفضلة', 'success');
    } else {
      newFavorites = [...favorites, gameId];
      showNotification('تم إضافة اللعبة للمفضلة', 'success');
    }
    setFavorites(newFavorites);
    localStorage.setItem('favoriteGames', JSON.stringify(newFavorites));
  };

  // Live filtering based on search and platform
  useEffect(() => {
    let result = [...games];

    // Apply search filter
    if (searchQuery.trim()) {
      const query = searchQuery.toLowerCase();
      result = result.filter(game => 
        game.title.toLowerCase().includes(query) ||
        game.description.toLowerCase().includes(query) ||
        game.platform.toLowerCase().includes(query)
      );
    }

    // Apply platform filter
    if (selectedPlatform) {
      result = result.filter(game => game.platform === selectedPlatform);
    }

    setFilteredGames(result);

    // Smooth scroll to products when searching
    if (searchQuery.trim() && productsRef.current) {
      setTimeout(() => {
        productsRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }, 100);
    }
  }, [searchQuery, selectedPlatform, games]);

  const fetchGames = async () => {
    try {
      const response = await gamesAPI.getGames({});
      setGames(response.data);
      setFilteredGames(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching games:', error);
      setLoading(false);
